    googleSocket.onerror = (e) => console.error("--- [GOOGLE WS ERROR] ---", e);

    clientSocket.onclose = () => {
      console.log("--- [RELAY] ⚪ Android App Disconnected ---");
      if (googleSocket.readyState === WebSocket.OPEN) googleSocket.close();
    };
  };

  return response;
});
